function solve(nums1) {
    const n = nums1.length;

    // Helper function to check if all elements in an array are of the same parity
    const checkParity = (arr) => {
        if (arr.length === 0) return true;
        const initialParity = arr[0] % 2;
        for (let i = 1; i < arr.length; i++) {
            if ((arr[i] % 2 + 2) % 2 !== (initialParity + 2) % 2) {
                return false;
            }
        }
        return true;
    };

    // The problem requires constructing nums2 such that all elements are either odd or all are even.
    // For each i, nums2[i] is either nums1[i] or nums1[i] - nums1[j] (j != i).

    // Since n is small (<= 100), we can iterate through all possible target parities (Even or Odd)
    // and for each parity, check if a valid construction exists.

    // We only need to check two cases:
    // Case 1: All elements of nums2 must be EVEN.
    // Case 2: All elements of nums2 must be ODD.

    /**
     * Tries to construct nums2 such that all elements have the target parity.
     * @param {number} targetParity 0 for Even, 1 for Odd.
     * @returns {boolean} True if such a construction exists.
     */
    const canAchieveParity = (targetParity) => {
        // For each index i, we need to find an option for nums2[i] that matches targetParity.
        // We must find one choice for each i such that they are all consistent.

        // Since the choice for each i is independent (we just need to *find* a valid sequence),
        // we check if for every i, at least one option leads to the target parity.

        for (let i = 0; i < n; i++) {
            let canMatch = false;

            // Option 1: nums2[i] = nums1[i]
            const parity1 = (nums1[i] % 2 + 2) % 2;
            if (parity1 === targetParity) {
                canMatch = true;
            }

            // Option 2: nums2[i] = nums1[i] - nums1[j] for some j != i
            if (!canMatch) {
                for (let j = 0; j < n; j++) {
                    if (i === j) continue;

                    const diff = nums1[i] - nums1[j];
                    const parity2 = (diff % 2 + 2) % 2;
                    if (parity2 === targetParity) {
                        canMatch = true;
                        break; // Found a valid j for this i
                    }
                }
            }

            // If for any i, we cannot achieve the target parity with any choice, this target parity is impossible.
            if (!canMatch) {
                return false;
            }
        }
        // If we passed the check for all i, a construction is possible for this target parity.
        return true;
    };

    // Check for Even parity (targetParity = 0) OR Odd parity (targetParity = 1)
    return canAchieveParity(0) || canAchieveParity(1);
}

